// Initialize LCD display
void LCD_Init(void) {
    // Initialize LCD hardware
    ST7735_InitR(INITR_REDTAB);
    
    // Set display orientation and clear screen
    ST7735_SetRotation(1);
    ST7735_FillScreen(ST7735_BLACK);
    
    // Set text color
    ST7735_SetTextColor(ST7735_WHITE);
}

// print the preprogrammed image
void LCD_ShowImage(void) {
    ST7735_DrawBitmap(30, 100, output_24bit, 50, 50);
}

// Update LCD with ADC voltage readings and conversion time
void LCD_UpdateADCReadings(void) {
    char buffer[32];
    
    // Display channel 0 average voltage
    ST7735_SetCursor(0, 0);
    float voltage0 = ADC_GetChannelAvgVoltage(0);
    uint32_t mv0 = (uint32_t)(voltage0 * 1000); // Convert to millivolts
    sprintf(buffer, "CH0:%lumV", mv0);
    ST7735_OutString(buffer);
    
    // Display channel 1 average voltage
    ST7735_SetCursor(0, 1);
    float voltage1 = ADC_GetChannelAvgVoltage(1);
    uint32_t mv1 = (uint32_t)(voltage1 * 1000);
    sprintf(buffer, "CH1:%lumV", mv1);
    ST7735_OutString(buffer);
    
    // Display channel 2 average voltage
    ST7735_SetCursor(0, 2);
    float voltage2 = ADC_GetChannelAvgVoltage(2);
    uint32_t mv2 = (uint32_t)(voltage2 * 1000);
    sprintf(buffer, "CH2:%lumV", mv2);
    ST7735_OutString(buffer);
    
    // Display ADC conversion time
    ST7735_SetCursor(0, 3);
    uint32_t convTime = ADC_GetConversionTime();
    sprintf(buffer, "Time:%luus", convTime);
    ST7735_OutString(buffer);
}
